DO $$
DECLARE
  p_CategoryID_fa05bd6f UUID;
  p_Name_fa05bd6f VARCHAR(425);
  p_Description_fa05bd6f TEXT;
  p_Type_fa05bd6f VARCHAR(20);
  p_UserPrompt_fa05bd6f TEXT;
  p_UserComments_fa05bd6f TEXT;
  p_Code_fa05bd6f TEXT;
  p_CodeComments_fa05bd6f TEXT;
  p_CodeApprovalStatus_fa05bd6f VARCHAR(20);
  p_CodeApprovalComments_fa05bd6f TEXT;
  p_CodeApprovedByUserID_fa05bd6f UUID;
  p_CodeApprovedAt_fa05bd6f TIMESTAMPTZ;
  p_CodeLocked_fa05bd6f BOOLEAN;
  p_ForceCodeGeneration_fa05bd6f BOOLEAN;
  p_RetentionPeriod_fa05bd6f INTEGER;
  p_Status_fa05bd6f VARCHAR(20);
  p_DriverClass_fa05bd6f VARCHAR(255);
  p_ParentID_fa05bd6f UUID;
  p_IconClass_fa05bd6f VARCHAR(100);
  p_DefaultCompactPromptID_fa05bd6f UUID;
  p_Config_fa05bd6f TEXT;
  p_RuntimeActionConfiguration_fa05bd6f TEXT;
  p_MaxExecutionTimeMS_fa05bd6f INTEGER;
  p_CreatedByAgentID_fa05bd6f UUID;
  p_ID_fa05bd6f UUID;
BEGIN
  p_CategoryID_fa05bd6f := '22285832-93AD-427E-81BA-E332F63FC5B9';
  p_Name_fa05bd6f := 'Entity Data Quality Report';
  p_Description_fa05bd6f := 'Scans a sample of records for a given entity and returns a data quality report: per-field null rates, distinct value counts, and an overall completeness score (0-1) that weights non-nullable fields 2x. Useful for data stewards triaging bad data. Exercises the `md` (entity introspection) and `rv` (RunView) bridge namespaces.';
  p_Type_fa05bd6f := 'Runtime';
  p_Code_fa05bd6f := '// Entity Data Quality Report — md + rv Runtime action.
//
// Given an entity name (and optional filter + sample size), scans records
// and reports per-field null rate, distinct value count, and an overall
// completeness score. Uses permissioned introspection via `utilities.md`
// and a read via `utilities.rv."RunView"`.
//
// The overall completeness score weights non-nullable fields 2x — missing
// values in fields that aren''t supposed to be null are a bigger quality
// signal than nulls in optional fields.

const _ = require(''lodash'');

const {
    entityName,
    extraFilter,
    sampleSize = 1000
} = input;

if (!entityName) {
    return { success: false, error: ''entityName is required'' };
}

// Step 1 — fetch the entity''s field metadata. This call goes through the
// bridgeWITH allowAnyEntity=true in the config it''s permitted for any
// entity. Without that flag it would be rejected unless the entity is in
// allowedEntities.
const fields = await utilities.md."GetEntityFields"(entityName);
if (!Array.isArray(fields) || fields.length === 0) {
    return {
        success: false,
        error: `No fields returned for entity ''$' || '{entityName}''. Check that the entity exists and the runtime action has permission to access it.`
    };
}

// Step 2 — pull up to sampleSize records matching the optional filter.
const viewResult = await utilities.rv."RunView"({
    EntityName: entityName,
    ExtraFilter: extraFilter,
    MaxRows: Number(sampleSize) || 1000
});

if (!viewResult."Success") {
    return {
        success: false,
        error: `RunView failed: $' || '{viewResult."ErrorMessage"}`,
        entityName
    };
}

const rows = viewResult."Results";
const totalRows = rows.length;

// Note whether the sample is complete or truncated — TotalRowCount comes
// back from RunView even when we capped MaxRows, so we can tell the user
// whether they''re getting a full scan or a sample.
const cappedAt = Number(sampleSize) || 1000;
const sampleNote = totalRows >= cappedAt && viewResult."TotalRowCount" > cappedAt
    ? `Sampled $' || '{cappedAt} of $' || '{viewResult."TotalRowCount"} rows — results are an estimate.`
    : `Scanned all $' || '{totalRows} rows.`;

// Step 3 — per-field analysis. We skip virtual fields (calculated at read
// time; null rates aren''t meaningful) and system timestamp fields.
const systemFields = new Set([''__mj_CreatedAt'', ''__mj_UpdatedAt'']);
const analyzable = fields.filter(
    (f) => !f."IsVirtual" && !systemFields.has(f."Name")
);

const byField = analyzable.map((f) => {
    const values = rows.map((r) => r[f."Name"]);
    const isEmpty = (v) => v == null || v === '''';
    const nullCount = values.filter(isEmpty).length;
    const nonEmpty = values.filter((v) => !isEmpty(v));
    // Distinct count — stringify objects so deep comparison isn''t needed.
    const distinctCount = new Set(
        nonEmpty.map((v) => (typeof v === ''object'' ? JSON.stringify(v) : v))
    ).size;
    const completeness = totalRows > 0 ? 1 - nullCount / totalRows : 1;

    return {
        field: f."Name",
        type: f."Type",
        allowsNull: f."AllowsNull",
        nullCount,
        nullRate: totalRows > 0 ? nullCount / totalRows : 0,
        distinctCount,
        distinctRatio: totalRows > 0 ? distinctCount / totalRows : 0,
        completeness
    };
});

// Step 4 — overall completeness score. Non-nullable fields weight 2x.
const nonNullable = byField.filter((f) => !f.allowsNull);
const nullable = byField.filter((f) => f.allowsNull);
const weightedSum =
    _.sumBy(nonNullable, (f) => f.completeness * 2) +
    _.sumBy(nullable, (f) => f.completeness);
const weightedCount = nonNullable.length * 2 + nullable.length;
const overallCompleteness = weightedCount > 0 ? weightedSum / weightedCount : 1;

// Step 5 — surface the 10 fields with the worst null rates for quick
// at-a-glance triage.
const worstFields = _.orderBy(
    byField.filter((f) => f.nullRate > 0),
    ''nullRate'',
    ''desc''
).slice(0, 10);

return {
    success: true,
    entityName,
    sampleNote,
    rowsAnalyzed: totalRows,
    totalRowsInEntity: viewResult."TotalRowCount",
    overallCompleteness: Number(overallCompleteness.toFixed(4)),
    fieldCount: byField.length,
    fieldsWithNulls: byField.filter((f) => f.nullCount > 0).length,
    worstFields,
    byField: _.orderBy(byField, ''field'')
};
';
  p_CodeApprovalStatus_fa05bd6f := 'Approved';
  p_CodeLocked_fa05bd6f := 0;
  p_ForceCodeGeneration_fa05bd6f := 0;
  p_Status_fa05bd6f := 'Active';
  p_IconClass_fa05bd6f := 'fa-solid fa-magnifying-glass-chart';
  p_RuntimeActionConfiguration_fa05bd6f := '{
  "permissions": {
    "allowedActions": [],
    "allowedAgents": [],
    "allowedEntities": [],
    "allowAnyEntity": true
  },
  "limits": {
    "maxMemoryMB": 256,
    "maxBridgeCalls": 10
  }
}';
  p_MaxExecutionTimeMS_fa05bd6f := 60000;
  p_ID_fa05bd6f := '1FA27C4C-34A7-4E1C-8134-6736F3781C8F';
  PERFORM __mj."spUpdateAction"(p_CategoryID := p_CategoryID_fa05bd6f, p_Name := p_Name_fa05bd6f, p_Description := p_Description_fa05bd6f, p_Type := p_Type_fa05bd6f, p_UserPrompt := p_UserPrompt_fa05bd6f, p_UserComments := p_UserComments_fa05bd6f, p_Code := p_Code_fa05bd6f, p_CodeComments := p_CodeComments_fa05bd6f, p_CodeApprovalStatus := p_CodeApprovalStatus_fa05bd6f, p_CodeApprovalComments := p_CodeApprovalComments_fa05bd6f, p_CodeApprovedByUserID := p_CodeApprovedByUserID_fa05bd6f, p_CodeApprovedAt := p_CodeApprovedAt_fa05bd6f, p_CodeLocked := p_CodeLocked_fa05bd6f, p_ForceCodeGeneration := p_ForceCodeGeneration_fa05bd6f, p_RetentionPeriod := p_RetentionPeriod_fa05bd6f, p_Status := p_Status_fa05bd6f, p_DriverClass := p_DriverClass_fa05bd6f, p_ParentID := p_ParentID_fa05bd6f, p_IconClass := p_IconClass_fa05bd6f, p_DefaultCompactPromptID := p_DefaultCompactPromptID_fa05bd6f, p_Config := p_Config_fa05bd6f, p_RuntimeActionConfiguration := p_RuntimeActionConfiguration_fa05bd6f, p_MaxExecutionTimeMS := p_MaxExecutionTimeMS_fa05bd6f, p_CreatedByAgentID := p_CreatedByAgentID_fa05bd6f, p_ID := p_ID_fa05bd6f);
END $$;

