  p_QueryID_4f9f3f0b := 'C0A11C4B-7C68-4A42-AC5E-F5268193CDAA';
  p_SQLDialectID_4f9f3f0b := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_4f9f3f0b := '-- PostgreSQL: Bulk lookup of RecordGeoCode rows for a single entity.
-- Returns lightweight fields needed for staleness checking and existence filtering.
-- Used by ScheduledGeocodingAction to eliminate per-record SQL queries.
SELECT
    rgc."ID",
    rgc."RecordID",
    rgc."LocationType",
    rgc."SourceFieldHash",
    rgc."Status"
FROM
    __mj."vwRecordGeoCodes" rgc
WHERE
    rgc."EntityID" = {{ EntityID | sqlString }}
ORDER BY
    rgc."RecordID"
';
  PERFORM __mj."spCreateQuerySQL"(p_ID := p_ID_4f9f3f0b, p_QueryID := p_QueryID_4f9f3f0b, p_SQLDialectID := p_SQLDialectID_4f9f3f0b, p_SQL := p_SQL_4f9f3f0b);
END $$;

-- Save MJ: Component Libraries (core SP call only)
DO $$
DECLARE
  p_Name_831d396d VARCHAR(500);
