  p_Category_831d396d VARCHAR(100);
  p_CDNUrl_831d396d VARCHAR(1000);
  p_CDNCssUrl_831d396d VARCHAR(1000);
  p_Description_831d396d TEXT;
  p_Status_831d396d VARCHAR(20);
  p_LintRules_831d396d TEXT;
  p_Dependencies_831d396d TEXT;
  p_UsageType_831d396d VARCHAR(50);
  p_UsageInstructions_831d396d TEXT;
  p_ID_831d396d UUID;
BEGIN
  p_Name_831d396d := 'chart.js';
  p_DisplayName_831d396d := 'Chart.js';
  p_Version_831d396d := '4.4.1';
  p_GlobalVariable_831d396d := 'Chart';
  p_Category_831d396d := 'Charting';
  p_CDNUrl_831d396d := 'https://unpkg.com/chart.js@4.4.1/dist/chart.umd.js';
  p_Description_831d396d := 'Simple yet flexible JavaScript charting library';
  p_Status_831d396d := 'Active';
  p_LintRules_831d396d := '{"initialization":{"constructorName":"Chart","requiresNew":true,"elementType":"canvas","requiredConfig":["type","data"]},"lifecycle":{"cleanupMethods":["destroy"],"updateMethods":["update"],"requiredMethods":[]},"validators":{"checkDestroyBeforeRecreate":{"description":"Ensure Chart instances are destroyed before recreating on same canvas.","severity":"high","validate":"/**\n * Ensure Chart instances are destroyed before recreating on same canvas\n * @param {Object} ast - The full AST\n * @param {Object} path - Current node path being validated\n * @param {Object} t - Babel types\n * @param {Object} context - Additional context with libraryName, globalVariable, instanceVariables\n * @returns {Object|null} Violation object or null if valid\n */\n(ast, path, t, context) => {\n  if (t.isNewExpression(path.node) && \n      t.isIdentifier(path.node.callee) && \n      path.node.callee.name === ''Chart'') {\n    \n    // Check if we''re in a useEffect\n    let inUseEffect = false;\n    let useEffectPath = path;\n    while (useEffectPath) {\n      if (t.isCallExpression(useEffectPath.node) && \n          t.isIdentifier(useEffectPath.node.callee) &&\n          useEffectPath.node.callee.name === ''useEffect'') {\n        inUseEffect = true;\n        break;\n      }\n      useEffectPath = useEffectPath.parentPath;\n    }\n    \n    if (inUseEffect) {\n      // Look for cleanup function return\n      let hasCleanup = false;\n      const effectFn = useEffectPath.node.arguments[0];\n      if (t.isArrowFunctionExpression(effectFn) || t.isFunctionExpression(effectFn)) {\n        // Check if it returns a cleanup function\n        const body = effectFn.body;\n        if (t.isBlockStatement(body)) {\n          for (const stmt of body.body) {\n            if (t.isReturnStatement(stmt) && stmt.argument) {\n              hasCleanup = true;\n              break;\n            }\n          }\n        }\n      }\n      \n      if (!hasCleanup) {\n        return {\n          rule: ''chart-missing-cleanup'',\n          severity: ''high'',\n          message: ''Chart.js instances must be destroyed in useEffect cleanup to prevent memory leaks'',\n          line: path.node.loc?.start.line || 0,\n          column: path.node.loc?.start.column || 0,\n          fix: ''return () => { chartInstance.current?.destroy(); }''\n        };\n      }\n    }\n  }\n  return null;\n}"},"checkCanvasContext":{"description":"Validate canvas context is obtained correctly","severity":"high","validate":"/**\n * Validate canvas context is obtained correctly\n * @param {Object} ast - The full AST\n * @param {Object} path - Current node path being validated\n * @param {Object} t - Babel types\n * @param {Object} context - Additional context\n * @returns {Object|null} Violation object or null if valid\n */\n(ast, path, t, context) => {\n  if (t.isNewExpression(path.node) && \n      t.isIdentifier(path.node.callee) && \n      path.node.callee.name === ''Chart'' &&\n      path.node.arguments[0]) {\n    \n    const firstArg = path.node.arguments[0];\n    \n    // Check if it''s a getContext(''2d'') call\n    if (t.isCallExpression(firstArg) &&\n        t.isMemberExpression(firstArg.callee) &&\n        t.isIdentifier(firstArg.callee.property) && \n        firstArg.callee.property.name === ''getContext'') {\n      \n      const contextArg = firstArg.arguments[0];\n      if (!t.isStringLiteral(contextArg) || contextArg.value !== ''2d'') {\n        return {\n          rule: ''chart-invalid-context'',\n          severity: ''high'',\n          message: ''Chart.js requires a 2D canvas context'',\n          line: contextArg?.loc?.start.line || 0,\n          column: contextArg?.loc?.start.column || 0,\n          fix: \"getContext(''2d'')\"\n        };\n      }\n    }\n  }\n  return null;\n}"},"checkChartRegistration":{"description":"Check for Chart.register() when using tree-shaking","severity":"medium","validate":"/**\n * Check for Chart.register() when using tree-shaking\n * @param {Object} ast - The full AST\n * @param {Object} path - Current node path being validated\n * @param {Object} t - Babel types\n * @param {Object} context - Additional context\n * @returns {Object|null} Violation object or null if valid\n */\n(ast, path, t, context) => {\n  // Only check if we see specific controller imports\n  if (t.isImportDeclaration(path.node) &&\n      path.node.source.value === ''chart.js/auto'') {\n    return null; // auto import includes everything\n  }\n  \n  if (t.isImportDeclaration(path.node) &&\n      path.node.source.value === ''chart.js'' &&\n      path.node.specifiers.some(spec => \n        t.isImportSpecifier(spec) &&\n        t.isIdentifier(spec.imported) &&\n        [''BarController'', ''LineController'', ''PieController''].includes(spec.imported.name)\n      )) {\n    \n    // Look for Chart.register call\n    let hasRegister = false;\n    ast.program.body.forEach(node => {\n      if (t.isExpressionStatement(node) &&\n          t.isCallExpression(node.expression) &&\n          t.isMemberExpression(node.expression.callee) &&\n          t.isIdentifier(node.expression.callee.object) &&\n          node.expression.callee.object.name === ''Chart'' &&\n          t.isIdentifier(node.expression.callee.property) &&\n          node.expression.callee.property.name === ''register'') {\n        hasRegister = true;\n      }\n    });\n    \n    if (!hasRegister) {\n      return {\n        rule: ''chart-missing-registration'',\n        severity: ''medium'',\n        message: ''When importing specific Chart.js components, you must call Chart.register()'',\n        line: path.node.loc?.start.line || 0,\n        column: path.node.loc?.start.column || 0,\n        fix: ''Chart.register(BarController, CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);''\n      };\n    }\n  }\n  return null;\n}"},"checkCanvasContainer":{"description":"Validate canvas parent has position: relative and explicit height for Chart.js rendering","severity":"high","validate":"/**\n * Validate that the Chart.js canvas parent container has position: ''relative''\n * and an explicit height. Without these, Chart.js renders into a 0-height or\n * collapsed container, producing a blank canvas.\n *\n * @param {Object} ast - The full AST\n * @param {Object} path - Current node path being validated\n * @param {Object} t - Babel types\n * @param {Object} context - Additional context with libraryName, globalVariable, instanceVariables\n * @returns {Object|null} Violation object or null if valid\n */\n(ast, path, t, context) => {\n  // Only trigger on <canvas> JSXOpeningElements that have a ref attribute\n  if (!t.isJSXOpeningElement(path.node) ||\n      !t.isJSXIdentifier(path.node.name) ||\n      path.node.name.name !== ''canvas'') {\n    return null;\n  }\n\n  const hasRef = path.node.attributes.some(attr =>\n    t.isJSXAttribute(attr) &&\n    t.isJSXIdentifier(attr.name) &&\n    attr.name.name === ''ref''\n  );\n\n  if (!hasRef) return null;\n\n  // Walk up from the canvas JSXElement to find the nearest parent JSXElement\n  // path is JSXOpeningElement -> parentPath is the canvas JSXElement\n  let walker = path.parentPath?.parentPath;\n  let parentJSX = null;\n  while (walker) {\n    if (t.isJSXElement(walker.node)) {\n      parentJSX = walker;\n      break;\n    }\n    walker = walker.parentPath;\n  }\n\n  if (!parentJSX) return null;\n\n  const openingEl = parentJSX.node.openingElement;\n\n  // Extract the ObjectExpression from an inline style={{ ... }} attribute\n  const styleAttr = openingEl.attributes.find(attr =>\n    t.isJSXAttribute(attr) &&\n    t.isJSXIdentifier(attr.name) &&\n    attr.name.name === ''style''\n  );\n\n  if (!styleAttr ||\n      !t.isJSXExpressionContainer(styleAttr.value) ||\n      !t.isObjectExpression(styleAttr.value.expression)) {\n    // No inline style object at all\n    return {\n      rule: ''chart-canvas-container'',\n      severity: ''high'',\n      message: \"Chart.js canvas container must have an inline style with position: ''relative'' and explicit height\",\n      line: openingEl.loc?.start.line || 0,\n      column: openingEl.loc?.start.column || 0,\n      fix: \"<div style={{ position: ''relative'', width: ''100%'', height: ''300px'' }}>\"\n    };\n  }\n\n  const styleObj = styleAttr.value.expression;\n\n  // Check for position: ''relative''\n  const hasPosition = styleObj.properties.some(prop =>\n    t.isObjectProperty(prop) &&\n    t.isIdentifier(prop.key) &&\n    prop.key.name === ''position'' &&\n    t.isStringLiteral(prop.value) &&\n    prop.value.value === ''relative''\n  );\n\n  // Check for explicit height (any value type is fine — string, number, expression)\n  const hasHeight = styleObj.properties.some(prop =>\n    t.isObjectProperty(prop) &&\n    t.isIdentifier(prop.key) &&\n    prop.key.name === ''height''\n  );\n\n  const missing = [];\n  if (!hasPosition) missing.push(\"position: ''relative''\");\n  if (!hasHeight) missing.push(\"explicit height (e.g. height: ''300px'')\");\n\n  if (missing.length > 0) {\n    return {\n      rule: ''chart-canvas-container'',\n      severity: ''high'',\n      message: `Chart.js canvas container is missing $' || '{missing.join('' and '')}. Without these the chart renders as a blank/collapsed canvas.`,\n      line: openingEl.loc?.start.line || 0,\n      column: openingEl.loc?.start.column || 0,\n      fix: \"<div style={{ position: ''relative'', width: ''100%'', height: ''300px'' }}>\"\n    };\n  }\n\n  return null;\n}\n"}}}';
  p_UsageType_831d396d := 'Both';
  p_UsageInstructions_831d396d := '## Canvas Container Requirements (CRITICAL)

When using Chart.js directly, the canvas element MUST be wrapped in a container with:

- `position: ''relative''` -- Chart.js requires this for responsive sizing
- Explicit height (e.g. `height: ''300px''` or `` height: `$' || '{height}px` ``) -- without this the canvas collapses to 0px
- `width: ''100%''` -- fills parent width

### Pattern

```jsx
<div style={{ width: ''100%'', height: ''300px'', position: ''relative'' }}>
  <canvas ref={canvasRef} />
</div>
```

### Chart.js Config

Always include in chart options:

```js
options: {
  responsive: true,
  maintainAspectRatio: false,
}
```

## Lifecycle

- Always destroy chart instances in the useEffect cleanup to prevent memory leaks
- Use a ref to store the chart instance: `chartRef.current = new Chart(...)`
- Cleanup: `return () => { chartRef.current?.destroy(); }`

## Access Pattern

- Use as global: `new Chart(canvasRef.current, config)`
- Do NOT use `window."Chart"`
- Do NOT use `unwrapLibraryComponents` -- Chart.js is a utility library
';
