  p_Description_737f4da2 TEXT;
  p_Type_737f4da2 VARCHAR(255);
  p_Status_737f4da2 VARCHAR(50);
  p_DeveloperName_737f4da2 VARCHAR(255);
  p_DeveloperEmail_737f4da2 VARCHAR(255);
  p_DeveloperOrganization_737f4da2 VARCHAR(255);
