  p_HasCustomEvents_f2dcdeb3 BOOLEAN;
  p_RequiresData_f2dcdeb3 BOOLEAN;
  p_DependencyCount_f2dcdeb3 INTEGER;
  p_TechnicalDesignVectorEmbeddingModelID_f2dcdeb3 TEXT;
  p_FunctionalRequirementsVectorEmbeddingModelID_f2dcdeb3 TEXT;
  p_HasRequiredCustomProps_f2dcdeb3 BOOLEAN;
  p_ID_f2dcdeb3 UUID;
BEGIN
  p_Namespace_f2dcdeb3 := 'Generic/UI/Chart';
  p_Name_f2dcdeb3 := 'SimpleChart';
  p_Version_f2dcdeb3 := '1.0.0';
  p_VersionSequence_f2dcdeb3 := 1;
  p_Title_f2dcdeb3 := 'Simple Chart';
  p_Description_f2dcdeb3 := 'Standalone single-level chart component with NO built-in drill-down functionality. Renders bar/line/pie/doughnut/area/scatter charts using Chart.js 4.4.1. Emits onClick events but doesn''t handle navigation - parent component must wire up drill-down logic.

#### SimpleChart - ONLY use when:
✅ Single data series (one line, one set of bars, one pie)
✅ No built-in drill-down needed (parent handles onClick)
✅ Standard chart types (bar, line, pie, doughnut, area, scatter)

❌ DO NOT USE SimpleChart when:
- Multiple series on same chart (e.g., "this year vs last year", "revenue AND count")
- Dual Y-axes needed
- Complex legend with multiple data series
- Any multi-dimensional comparison
- User explicitly wants ''drill-down to table'' (use SimpleDrilldownChart instead)

**Use For:** standalone visualizations, dashboard widgets, building blocks in custom multi-level drill-downs.

Auto-aggregates data client-side by groupBy field with count/sum/average/min/max methods. Smart auto-type selection: date fields→line, ≤5 categories→pie (preferred over doughnut), else→bar. Single-series bar charts use different colors for each bar. Formats values automatically: currency ($ for Amount fields), dates (locale format), numbers (commas). Exports as PNG image. Click events highlight the selected element and return {label, value, records: Array<object>, percentage} for parent to implement custom drill logic. No re-animation on element clicks.

**Layout:** SimpleChart manages its own height via the `height` prop (default 400px). To control chart size, pass `height` directly — do not use a fixed-height wrapper div.
';
  p_Type_f2dcdeb3 := 'Chart';
  p_Status_f2dcdeb3 := 'Published';
  p_Specification_f2dcdeb3 := '{"name":"SimpleChart","title":"Simple Chart","description":"Standalone single-level chart component with NO built-in drill-down functionality. Renders bar/line/pie/doughnut/area/scatter charts using Chart.js 4.4.1. Emits onClick events but doesn''t handle navigation - parent component must wire up drill-down logic.\n\n#### SimpleChart - ONLY use when:\n✅ Single data series (one line, one set of bars, one pie)\n✅ No built-in drill-down needed (parent handles onClick)\n✅ Standard chart types (bar, line, pie, doughnut, area, scatter)\n\n❌ DO NOT USE SimpleChart when:\n- Multiple series on same chart (e.g., \"this year vs last year\", \"revenue AND count\")\n- Dual Y-axes needed\n- Complex legend with multiple data series\n- Any multi-dimensional comparison\n- User explicitly wants ''drill-down to table'' (use SimpleDrilldownChart instead)\n\n**Use For:** standalone visualizations, dashboard widgets, building blocks in custom multi-level drill-downs.\n\nAuto-aggregates data client-side by groupBy field with count/sum/average/min/max methods. Smart auto-type selection: date fields→line, ≤5 categories→pie (preferred over doughnut), else→bar. Single-series bar charts use different colors for each bar. Formats values automatically: currency ($ for Amount fields), dates (locale format), numbers (commas). Exports as PNG image. Click events highlight the selected element and return {label, value, records: Array<object>, percentage} for parent to implement custom drill logic. No re-animation on element clicks.\n\n**Layout:** SimpleChart manages its own height via the `height` prop (default 400px). To control chart size, pass `height` directly — do not use a fixed-height wrapper div.\n","type":"chart","location":"embedded","functionalRequirements":"## Purpose\nStandalone single-series chart component with **NO built-in drill-down**. Renders bar/line/pie/doughnut/area/scatter charts using Chart.js 4.4.1. Emits onClick events but doesn''t handle navigation - parent component must wire up drill-down logic.\n\n## Data Requirements\n- **Input**: Array of objects (detail-level records)\n- **Aggregation**: Component performs client-side aggregation (groups by field, applies count/sum/average/min/max)\n- **Optional**: `entityName` for metadata-driven field type detection\n\n## Chart Types & Auto-Selection\n\n### Supported Types\n- **bar** (default): Vertical bars, each bar gets different color in single-series\n- **column**: Alias for bar\n- **line**: Connected line chart, single color\n- **pie** (preferred over doughnut): Circular chart, each slice gets different color\n- **doughnut** (donut): Ring chart with center hole, each slice gets different color\n- **area**: Line chart with filled area below\n- **scatter**: Points without connecting lines\n\n### Auto-Type Selection Logic\nIf `chartType` prop omitted, component intelligently selects type:\n\n1. **Date field detected** → line chart\n   - Checks entity metadata (Type = ''datetime'' or ''date'')\n   - OR value is Date instance\n   - OR string parseable as date\n   \n2. **≤ 5 categories** after aggregation → pie chart\n   - Preferred over doughnut for clarity\n   - Better for small datasets\n\n3. **Else** → bar chart (default)\n   - Best for general comparison\n\n## Data Aggregation\n\n### Configuration\n- **groupBy** (required): Field name to group records by\n- **valueField** (optional): Field to aggregate (required for sum/average/min/max)\n- **aggregateMethod**: count | sum | average | min | max (default: count)\n\n### Methods\n\n1. **count** (default): Counts records per group\n   - No valueField needed\n   - Example: \"Count of orders by status\"\n\n2. **sum**: Sums valueField for each group\n   - Example: \"Total revenue by product category\"\n\n3. **average**: Averages valueField for each group\n   - Example: \"Average deal size by region\"\n\n4. **min**: Minimum valueField value per group\n   - Example: \"Lowest price by supplier\"\n\n5. **max**: Maximum valueField value per group\n   - Example: \"Highest score by student\"\n\n### Date Field Handling\nWhen groupBy field is date/datetime:\n- Groups by ISO date string (YYYY-MM-DD) for consistent grouping\n- Formats labels as locale-specific dates (e.g., \"Jan 15, 2024\")\n- Preserves chronological order\n\n## Sorting & Limiting\n\n### Sorting\n**Default behavior** (sortBy=undefined):\n- **Preserves input data order**\n- Ideal for time-series (pre-sort by date in query)\n- Ideal when query already returns desired order\n\n**Explicit sorting**:\n- `sortBy=''value''`: Sorts by aggregated values (for rankings like \"top products\")\n- `sortBy=''label''`: Sorts alphabetically by category labels\n- `sortOrder=''asc'' | ''desc''`: Controls direction\n\n### Top-N Limiting\n`limit={10}`: Shows only top N categories after sorting\n- Common pattern: `sortBy=''value'' sortOrder=''desc'' limit={10}` for \"Top 10\"\n\n## Value Formatting\n\n### Automatic Detection\n- **Dates**: toLocaleDateString (month short, day, year) → \"Jan 15, 2024\"\n- **Currency**: Intl."NumberFormat" USD style → \"$1,234.56\"\n  - Detected when: valueField is ''money'' type OR field name includes \"amount\"/\"price\"/\"cost\"\n- **Numbers**: Intl."NumberFormat" with commas → \"1,234\"\n- **Null**: \"N/A\"\n\n## Color System\n\n### Single-Series Bar Charts\n- **Each bar gets different color** for visual distinction\n- Uses color palette from `colors` prop or default palette\n- Example: Category A (blue), Category B (green), Category C (orange)\n\n### Pie/Doughnut Charts\n- Each slice gets different color from palette\n- Consistent color assignment per data point\n\n### Line/Area Charts\n- Single color (first from palette)\n- Optional fill for area charts\n\n### Custom Colors\n`colors={"''#FF6384'', ''#36A2EB'', ''#FFCE56''"}`:\n- Array of hex colors\n- Applied in order to data points\n\n## Click Interaction\n\n### Element Highlighting\n- Clicked element highlighted with **3x thicker border**\n- Border persists until another element clicked\n- Visual feedback confirms selection\n\n### No Re-animation on Click\n- Chart animates once on initial render (750ms)\n- Subsequent clicks update **without animation** (instant)\n- Prevents jarring re-animation effect\n\n### onClick Event\n`onDataPointClick` fires with rich context:\n```javascript\n{\n  chartType: ''bar'',\n  series: ''Revenue'', // valueField or ''Count''\n  label: ''Electronics'', // Category name\n  value: 1234.56, // Aggregated value\n  records: "...", // Array of ALL records in this segment\n  percentage: 23.5 // Percentage of total\n}\n```\n\n**Parent must handle**: SimpleChart only emits event, doesn''t navigate\n- Show DataGrid with filtered records\n- Navigate to detail page\n- Render child SimpleChart with filtered data\n- Open modal/sidebar\n- Apply filters to other components\n\n## Features\n\n### Legend\n- **position**: ''auto'' (default), ''top'', ''bottom'', ''left'', ''right''\n- **fontSize**: Configurable legend text size\n- **show**: true/false to toggle visibility\n\n### Data Labels\n`showDataLabels={true}`:\n- Shows values directly on chart elements\n- Positioned automatically by Chart.js\n- Format uses same value formatting logic\n\n### Export\n`enableExport={true}`:\n- Shows \"⬇ Export\" button overlay (top-right)\n- Downloads chart as PNG image\n- Uses canvas.toDataURL(''image/png'')\n- Filename: auto-generated or custom\n\n### Loading State\nShows spinner while processing data.\n\n### Empty State\nGray background with \"No data available\" when no records.\n\n### Error Handling\n- Validates groupBy field exists in data\n- Shows red error panel with available fields if validation fails\n- Gracefully handles missing Chart.js library\n\n## Visual Configuration\n\n### Chart Height\n`height` prop: Sets canvas height (default 400px)\n\n### Responsive\n- Chart resizes with container width\n- maintainAspectRatio: false (fills container)\n\n### Hover Effects\n- Cursor changes to pointer over data points\n- Tooltip shows on hover (label + formatted value)\n- Hover mode: ''nearest'' for precise targeting\n\n## Metadata Integration\nWhen `entityName` provided:\n- Loads entity from `utilities.md."Entities"`\n- Uses field Type for auto-type detection\n- Uses field Type for value formatting\n- Enables smart currency/date/number formatting\n\n## Events\n\n1. **onDataPointClick**: Fired on chart element click\n   - Includes full segment data with records array\n   \n2. **onChartRendered**: Fired after successful render\n   - Includes `{chartType, dataPointCount, aggregateMethod, totalValue}`\n   \n3. **onError**: Fired if chart rendering fails\n\n## Use Cases\n- Dashboard widgets (view-only charts)\n- Building blocks for custom multi-level drill-downs\n- Charts requiring custom onClick handling\n- Reusable chart component in larger compositions\n- Export-only charts (generate reports)\n","technicalDesign":"## Architecture\nReact functional component using Chart.js 4.4.1 for canvas-based chart rendering with NO built-in drill-down (emits events only).\n\n## Dependencies\n- **Chart.js** (4.4.1): Canvas chart rendering (global: Chart)\n- Unwrapped via `unwrapLibraryComponents(Chart, ''Chart'')` to handle various package formats\n\n## State Management (React Hooks)\n- **error** (string | null): Error message if rendering fails\n- **entityInfo** (object | null): Entity metadata from `utilities.md."Entities"`\n\n## Refs\n- **canvasRef** (React.useRef): Reference to canvas element\n- **chartInstanceRef** (React.useRef): Reference to Chart.js instance (for updates/destroy)\n\n## Data Processing Pipeline (useMemo)\n\n### processData Function\n**Dependencies**: `data`, `groupBy`, `stackBy`, `valueField`, `aggregateMethod`, `sortBy`, `sortOrder`, `limit`, `entityInfo`\n\n**Process** (non-stacked mode - for stacked mode see \"Stacked Mode\" section below):\n1. **Validation**:\n   ```javascript\n   if (!data || data.length === 0) {\n     return { isEmpty: true };\n   }\n   if (!data[0]"groupBy") {\n     throw new Error(`Field ''$' || '{groupBy}'' not found. Available: $' || '{Object.keys(data[0]).join('', '')}`);\n   }\n   ```\n\n2. **Grouping** (handles date fields specially):\n   ```javascript\n   const groups = {};\n   data.forEach(record => {\n     let key = record"groupBy";\n     \n     // Special date handling\n     if (isDateField(groupBy)) {\n       key = new Date(key).toISOString().split(''T'')[0]; // YYYY-MM-DD\n     }\n     \n     if (!groups"key") {\n       groups"key" = [];\n     }\n     groups"key".push(record);\n   });\n   ```\n\n3. **Aggregation**:\n   ```javascript\n   const aggregated = Object.entries(groups).map(("label, records") => {\n     let value;\n     if (aggregateMethod === ''count'') {\n       value = records.length;\n     } else if (aggregateMethod === ''sum'') {\n       value = records.reduce((sum, r) => sum + (parseFloat(r"valueField") || 0), 0);\n     } else if (aggregateMethod === ''average'') {\n       const sum = records.reduce((s, r) => s + (parseFloat(r"valueField") || 0), 0);\n       value = sum / records.length;\n     } else if (aggregateMethod === ''min'') {\n       value = Math.min(...records.map(r => parseFloat(r"valueField") || 0));\n     } else if (aggregateMethod === ''max'') {\n       value = Math.max(...records.map(r => parseFloat(r"valueField") || 0));\n     }\n     \n     return { label, value, records };\n   });\n   ```\n\n4. **Sorting** (if sortBy specified):\n   ```javascript\n   if (sortBy === ''value'') {\n     aggregated.sort((a, b) => \n       sortOrder === ''asc'' ? a.value - b.value : b.value - a.value\n     );\n   } else if (sortBy === ''label'') {\n     aggregated.sort((a, b) => \n       sortOrder === ''asc'' \n         ? a.label.localeCompare(b.label)\n         : b.label.localeCompare(a.label)\n     );\n   }\n   // else: preserve original order\n   ```\n\n5. **Limiting** (top-N):\n   ```javascript\n   if (limit && limit > 0) {\n     aggregated = aggregated.slice(0, limit);\n   }\n   ```\n\n6. **Extract arrays**:\n   ```javascript\n   return {\n     categories: aggregated.map(item => item.label),\n     values: aggregated.map(item => item.value),\n     chartData: aggregated, // Full data for click events\n     isEmpty: false\n   };\n   ```\n\n## Stacked Mode (stackBy Property)\n\nWhen `stackBy` property is provided, the component creates a multi-series stacked bar chart with separate datasets for each unique stack value.\n\n### Stacked Data Processing\n**Dependencies**: `data`, `groupBy`, `stackBy`, `valueField`, `aggregateMethod`, `sortBy`, `sortOrder`, `limit`, `entityInfo`\n\n**Process**:\n1. **Collect primary categories** (X-axis values):\n   ```javascript\n   const categoriesSet = new Set();\n   data.forEach(record => {\n     let key = record"groupBy" || ''Unknown'';\n     // Apply date formatting if needed\n     if (isDateField) {\n       key = new Date(key).toISOString().split(''T'')[0];\n     }\n     categoriesSet.add(key);\n   });\n   let categories = Array.from(categoriesSet);\n   ```\n\n2. **Collect stack values** (series/colors):\n   ```javascript\n   const stackValuesSet = new Set();\n   data.forEach(record => {\n     const stackValue = record"stackBy" || ''Unknown'';\n     stackValuesSet.add(stackValue);\n   });\n   const stackValues = Array.from(stackValuesSet).sort();\n   ```\n\n3. **Group by BOTH dimensions**:\n   ```javascript\n   const grouped = {};\n   data.forEach(record => {\n     const categoryKey = record"groupBy" || ''Unknown'';\n     const stackValue = record"stackBy" || ''Unknown'';\n     const key = `$' || '{categoryKey}|||$' || '{stackValue}`; // Composite key\n\n     if (!grouped"key") {\n       grouped"key" = {\n         category: categoryKey,\n         stackValue: stackValue,\n         records: [],\n         value: 0\n       };\n     }\n     grouped"key".records.push(record);\n   });\n   ```\n\n4. **Aggregate each group** (same logic as non-stacked: count/sum/average/min/max)\n\n5. **Create datasets array** - one dataset per stack value:\n   ```javascript\n   const datasets = stackValues.map((stackValue, stackIndex) => {\n     const datasetValues = categories.map(category => {\n       const key = `$' || '{category}|||$' || '{stackValue}`;\n       return grouped"key" ? grouped"key".value : 0; // Zero if no data\n     });\n\n     return {\n       label: String(stackValue),\n       data: datasetValues,\n       backgroundColor: (colors || defaultColors)"stackIndex % (colors || defaultColors).length",\n       borderColor: (colors || defaultColors)"stackIndex % (colors || defaultColors).length",\n       borderWidth: 1\n     };\n   });\n   ```\n\n6. **Return structure**:\n   ```javascript\n   return {\n     categories: categories.map(c => String(c)),\n     datasets: datasets, // Multiple datasets, one per stack value\n     values: [], // Not used in stacked mode\n     chartData: Object.values(grouped),\n     isEmpty: false\n   };\n   ```\n\n### Stacked Chart Configuration\nWhen `isStacked` is true (stackBy provided and datasets exist):\n```javascript\nconst config = {\n  type: ''bar'', // or ''line''\n  data: {\n    labels: processData.categories,\n    datasets: processData.datasets // Use pre-built datasets\n  },\n  options: {\n    scales: {\n      y: {\n        stacked: true, // Enable stacking on Y-axis\n        beginAtZero: true\n      },\n      x: {\n        stacked: true // Enable stacking on X-axis\n      }\n    }\n    // ... other options same as non-stacked\n  }\n};\n```\n\n**Key difference**: In non-stacked mode, there''s one dataset with different colors per bar. In stacked mode, each dataset has one color and represents a series across all categories.\n\n## Auto Chart Type Detection\n\n### determineChartType Function\n```javascript\nconst determineChartType = () => {\n  if (chartType) return chartType; // Explicit type takes priority\n  \n  // Check if groupBy is date field\n  if (isDateField(groupBy)) {\n    return ''line'';\n  }\n  \n  // Use pie for small number of categories (≤5, preferred over doughnut)\n  if (processData.categories && processData.categories.length <= 5) {\n    return ''pie'';\n  }\n  \n  // Default to bar\n  return ''bar'';\n};\n\n// Map aliases\nconst actualChartType = {\n  ''donut'': ''doughnut'',\n  ''column'': ''bar''\n}"determineChartType()" || determineChartType();\n```\n\n## Chart.js Configuration\n\n### Dataset Configuration\n```javascript\nconst datasets = "{\n  label: valueField || ''Count'',\n  data: processData.values,\n  backgroundColor: isPieOrDoughnut\n    ? (colors || defaultColors).slice(0, processData.values.length)\n    : isLineOrArea\n      ? ''rgba(24, 144, 255, 0.2)''\n      : (colors || defaultColors).slice(0, processData.values.length), // Different color per bar\n  borderColor: isPieOrDoughnut\n    ? undefined\n    : isLineOrArea\n      ? (colors || defaultColors)[0"\n      : (colors || defaultColors).slice(0, processData.values.length), // Different border per bar\n  borderWidth: isPieOrDoughnut ? 1 : 2,\n  fill: isLineOrArea ? true : false,\n  tension: isLineOrArea ? 0.4 : undefined\n}];\n```\n\n### Chart Options\n```javascript\nconst options = {\n  responsive: true,\n  maintainAspectRatio: false,\n  animation: {\n    duration: 750, // Initial animation\n    onComplete: () => {\n      // Disable animations after initial render to prevent re-animation on clicks\n      if (chartInstanceRef.current) {\n        chartInstanceRef.current.options.animation = false;\n      }\n    }\n  },\n  hover: {\n    mode: ''nearest'',\n    intersect: true\n  },\n  onHover: (event, activeElements) => {\n    // Change cursor to pointer when hovering over data points\n    event.native.target.style.cursor = activeElements.length > 0 ? ''pointer'' : ''default'';\n  },\n  onClick: (_event, elements) => {\n    if (elements && elements.length > 0 && onDataPointClick) {\n      const index = elements[0].index;\n      const clickedData = processData.chartData"index";\n      \n      // Highlight clicked element\n      if (chartInstanceRef.current) {\n        const meta = chartInstanceRef.current.getDatasetMeta(0);\n        const element = meta.data"index";\n        if (element) {\n          // Store original border width\n          if (!element._originalBorderWidth) {\n            element._originalBorderWidth = element.options.borderWidth || 1;\n          }\n          \n          // Reset all elements\n          meta.data.forEach((el) => {\n            if (el._originalBorderWidth) {\n              el.options.borderWidth = el._originalBorderWidth;\n            }\n          });\n          \n          // Highlight clicked element (3x thicker border)\n          element.options.borderWidth = element._originalBorderWidth * 3;\n          \n          // Update chart without animation\n          chartInstanceRef.current.update(''none'');\n        }\n      }\n      \n      onDataPointClick({\n        chartType: actualChartType,\n        series: valueField || ''Count'',\n        label: clickedData.label,\n        value: clickedData.value,\n        records: clickedData.records,\n        percentage: (clickedData.value / processData.values.reduce((a, b) => a + b, 0)) * 100\n      });\n    }\n  },\n  plugins: {\n    title: {\n      display: !!title,\n      text: title\n    },\n    legend: {\n      display: legend?.show !== false,\n      position: legend?.position || ''auto'',\n      labels: {\n        fontSize: legend?.fontSize || 12\n      }\n    },\n    tooltip: {\n      callbacks: {\n        label: (context) => {\n          const label = context.label || '''';\n          const value = formatValue(context.parsed.y || context.parsed);\n          return `$' || '{label}: $' || '{value}`;\n        }\n      }\n    },\n    datalabels: showDataLabels ? {\n      anchor: ''end'',\n      align: ''top'',\n      formatter: (value) => formatValue(value)\n    } : false\n  },\n  scales: !isPieOrDoughnut ? {\n    y: {\n      beginAtZero: true,\n      ticks: {\n        callback: (value) => formatValue(value)\n      }\n    },\n    x: {\n      ticks: {\n        maxRotation: 45,\n        minRotation: 0\n      }\n    }\n  } : undefined\n};\n```\n\n## Value Formatting\n\n### formatValue Function\n```javascript\nconst formatValue = (value) => {\n  if (value == null) return ''N/A'';\n  \n  // Check if date\n  if (value instanceof Date || !isNaN(Date.parse(value))) {\n    try {\n      return new Date(value).toLocaleDateString(''en-US'', {\n        month: ''short'',\n        day: ''numeric'',\n        year: ''numeric''\n      });\n    } catch {\n      // Not a date, continue\n    }\n  }\n  \n  // Check if currency\n  const isCurrency = valueField && (\n    valueField.toLowerCase().includes(''amount'') ||\n    valueField.toLowerCase().includes(''price'') ||\n    valueField.toLowerCase().includes(''cost'')\n  );\n  \n  if (isCurrency || (entityInfo && /* check Type === ''money'' */)) {\n    return new Intl."NumberFormat"(''en-US'', {\n      style: ''currency'',\n      currency: ''USD''\n    }).format(value);\n  }\n  \n  // Format as number with commas\n  return new Intl."NumberFormat"(''en-US'').format(value);\n};\n```\n\n## Chart Rendering (useEffect)\n\n### Dependencies\nRuns on: `processData`, `canvasRef`, `actualChartType`, `colors`, etc.\n\n### Process\n```javascript\nuseEffect(() => {\n  // Check empty state\n  if (processData.isEmpty || !canvasRef.current) return;\n  \n  // Validate Chart.js loaded\n  if (!Chart) {\n    setError(''Chart.js library not loaded'');\n    return;\n  }\n  \n  // Destroy existing chart\n  if (chartInstanceRef.current) {\n    chartInstanceRef.current.destroy();\n  }\n  \n  // Get canvas context\n  const ctx = canvasRef.current.getContext(''2d'');\n  \n  // Create new Chart.js instance\n  chartInstanceRef.current = new Chart(ctx, {\n    type: actualChartType,\n    data: {\n      labels: processData.categories,\n      datasets: "/* dataset config */"\n    },\n    options: {/* options config */}\n  });\n  \n  // Fire onChartRendered event\n  if (onChartRendered) {\n    onChartRendered({\n      chartType: actualChartType,\n      dataPointCount: processData.values.length,\n      aggregateMethod: aggregateMethod,\n      totalValue: processData.values.reduce((a, b) => a + b, 0)\n    });\n  }\n  \n  // Cleanup\n  return () => {\n    if (chartInstanceRef.current) {\n      chartInstanceRef.current.destroy();\n    }\n  };\n}, "/* dependencies */");\n```\n\n## Export Functionality (useEffect)\n\n### Implementation\n```javascript\nuseEffect(() => {\n  if (enableExport && canvasRef.current) {\n    const handleExport = () => {\n      const dataURL = canvasRef.current.toDataURL(''image/png'');\n      const a = document.createElement(''a'');\n      a.href = dataURL;\n      a.download = `chart-$' || '{Date.now()}.png`;\n      a.click();\n    };\n    \n    // Store in global for button access\n    window."SimpleChartExport" = handleExport;\n    \n    return () => {\n      delete window."SimpleChartExport";\n    };\n  }\n}, "enableExport, canvasRef");\n```\n\n## Render Output\n\n### Error State\n```javascript\nif (error) {\n  return (\n    <div style={{ \n      color: ''#EF4444'', \n      padding: ''20px'', \n      backgroundColor: ''#FEE2E2'',\n      height: height || ''400px'',\n      display: ''flex'',\n      alignItems: ''center'',\n      justifyContent: ''center''\n    }}>\n      {error}\n    </div>\n  );\n}\n```\n\n### Empty State\n```javascript\nif (processData.isEmpty) {\n  return (\n    <div style={{\n      backgroundColor: ''#F3F4F6'',\n      height: height || ''400px'',\n      display: ''flex'',\n      alignItems: ''center'',\n      justifyContent: ''center'',\n      color: ''#6B7280''\n    }}>\n      No data available\n    </div>\n  );\n}\n```\n\n### Success State\n```javascript\nreturn (\n  <div style={{ position: ''relative'', height: height || ''400px'' }}>\n    {enableExport && (\n      <button\n        onClick={() => window."SimpleChartExport" && window."SimpleChartExport"()}\n        style={{\n          position: ''absolute'',\n          top: ''10px'',\n          right: ''10px'',\n          zIndex: 10,\n          padding: ''6px 12px'',\n          backgroundColor: ''#3B82F6'',\n          color: ''white'',\n          border: ''none'',\n          borderRadius: ''4px'',\n          cursor: ''pointer''\n        }}\n      >\n        ⬇ Export\n      </button>\n    )}\n    <div style={{ height: ''100%'' }}>\n      <canvas ref={canvasRef}></canvas>\n    </div>\n  </div>\n);\n```\n\n## Performance Optimizations\n- Data processing memoized (useMemo) - only recalculates when dependencies change\n- Chart instance reused/updated when possible (destroy/recreate only when necessary)\n- Animation disabled after initial render (prevents re-animation on interactions)\n- Canvas rendering (hardware accelerated via Chart.js)\n- Efficient color slicing (no array copies)\n","dataRequirements":{"mode":"props","description":"Component receives entity data through props and performs client-side aggregation"},"properties":"{"name":"entityName","type":"string","description":"Optional entity name for metadata-aware formatting (dates, money, value lists). If omitted, component uses basic type detection and works with any data array. Note: This property is NOT used for generating the chart title - always provide an explicit ''title'' property to avoid undefined titles.","required":false},{"name":"data","type":"Array<object>","description":"Array of entity records to visualize. Typically detail-level records (invoices, transactions, events) that component will aggregate by groupBy field. Can also accept pre-aggregated data if you''re building custom charts without drill-down needs. For drill-down charts, use SimpleDrilldownChart which requires detail records.","required":true},{"name":"groupBy","type":"string","description":"Field name to group data by. Works with any field in the data array. In non-stacked mode, this is the primary (X-axis) grouping. In stacked mode (when stackBy is provided), this is still the primary X-axis grouping, and stackBy creates the color-coded series.","required":true},{"name":"stackBy","type":"string","description":"Optional secondary grouping field for stacked bar/column charts. When provided, creates a multi-series stacked chart where: (1) groupBy field defines X-axis categories, (2) stackBy field defines the colored series/layers within each bar. Example: groupBy=''Quarter'' and stackBy=''MeetingType'' creates bars for each quarter with stacked layers colored by meeting type. Each unique stackBy value becomes a separate dataset with its own color. Best for showing composition or breakdown within categories. Only works with bar/column chart types - pie/line charts ignore this property.","required":false},{"name":"valueField","type":"string","description":"Field name to aggregate for chart values. REQUIRED when using aggregateMethod ''sum'', ''average'', ''min'', or ''max''. OMIT when using ''count'' (counts records regardless of field values). Examples: ''Total'' for revenue, ''Amount'' for sales, ''Quantity'' for inventory. Component groups records by groupBy field and aggregates this valueField according to aggregateMethod.","required":false,"constraints":[{"type":"required-when","dependsOn":"aggregateMethod","description":"valueField is required when aggregateMethod is sum, average, min, or max","config":{"condition":"siblingProp === ''sum'' || siblingProp === ''average'' || siblingProp === ''min'' || siblingProp === ''max''"},"errorTemplate":"valueField is required when aggregateMethod is ''{aggregateMethod}''"}"},{"name":"aggregateMethod","type":"''count'' | ''sum'' | ''average'' | ''min'' | ''max''","description":"How to aggregate records within each group. CRITICAL: Choose based on what you''re measuring. Use ''count'' ONLY when counting records (omit valueField). Use ''sum'' for totals (revenue, sales, costs - REQUIRES valueField). Use ''average'' for means (average deal size, average rating). Use ''min''/''max'' for extremes. COMMON MISTAKE: Using default ''count'' when valueField is specified - this counts records instead of summing values! Example: For ''revenue by month'', use aggregateMethod=''sum'' with valueField=''Total'', NOT count.","required":false,"defaultValue":"count","possibleValues":""count","sum","average","min","max""},{"name":"chartType","type":"''auto'' | ''bar'' | ''line'' | ''pie'' | ''doughnut'' | ''area'' | ''scatter''","description":"Chart type to render. ''auto'' selects based on data","required":false,"defaultValue":"auto","possibleValues":""auto","bar","line","pie","doughnut","area","scatter""},{"name":"title","type":"string","description":"Chart title displayed above the chart. If not provided, no title will be shown. Best practice: Always provide a descriptive title when using the component to avoid undefined values in the display.","required":false},{"name":"height","type":"number","description":"Chart height in pixels. The chart renders at exactly this height. IMPORTANT: Do NOT wrap SimpleChart in a container with a different fixed height — this causes the chart to visually overflow and overlap sibling components. Either pass the desired height via this prop, or let the chart flow naturally without a height-constrained wrapper.","required":false,"defaultValue":400},{"name":"sortBy","type":"''label'' | ''value'' | undefined","description":"How to sort chart data. By default (undefined), input data order is PRESERVED - this is ideal for time-series data where your query already returns data sorted by date, or when you want full control over ordering. ''value'' sorts by aggregated values - useful for ranking charts (top products by revenue, most active users). ''label'' sorts alphabetically by category labels. IMPORTANT: If you pass pre-sorted time-series data, do NOT set sortBy - let it default to undefined to preserve your chronological ordering.","required":false,"defaultValue":"undefined","possibleValues":""label","value","undefined""},{"name":"sortOrder","type":"''asc'' | ''desc''","description":"Sort direction when sortBy is specified. ''asc'' = ascending (low to high, A to Z, old to new). ''desc'' = descending (high to low, Z to A, new to old). Only applies when sortBy is ''label'' or ''value''. For rankings with sortBy=''value'', typically use ''desc'' for highest-first (top 10 products). For alphabetical sorting with sortBy=''label'', use ''asc'' for A→Z.","required":false,"defaultValue":"asc","possibleValues":""asc","desc""},{"name":"limit","type":"number","description":"Limit number of data points shown (e.g., top 10)","required":false},{"name":"colors","type":"Array<string>","description":"Custom color palette for the chart","required":false},{"name":"showLegend","type":"boolean","description":"Whether to show the legend","required":false,"defaultValue":true},{"name":"legendPosition","type":"''auto'' | ''top'' | ''bottom'' | ''left'' | ''right''","description":"Position of the legend. ''auto'' uses bottom for pie/doughnut, top for others","required":false,"defaultValue":"auto","possibleValues":""auto","top","bottom","left","right""},{"name":"legendFontSize","type":"number","description":"Font size for legend labels in pixels","required":false,"defaultValue":12},{"name":"showDataLabels","type":"boolean","description":"Whether to show data labels on chart","required":false,"defaultValue":false},{"name":"enableExport","type":"boolean","description":"When true, displays an export button in the top-right corner above the chart to download chart as PNG image. Button is positioned outside the chart canvas to avoid overlaying the visualization.","required":false,"defaultValue":true}],"events":"{"name":"dataPointClick","description":"Fired when user clicks on a data point","parameters":[{"name":"clickData","type":"{ series: string; value: number; label: string; records: Array<object>; chartType: string; percentage?: number }","description":"Object containing series name, data value, label, original records, and chart type"}"},{"name":"chartRendered","description":"Fired when chart has finished rendering","parameters":"{"name":"chartInfo","type":"{ chartType: string; dataPointCount: number; aggregateMethod: string; totalValue: number }","description":"Information about the rendered chart including type, data point count, aggregation method, and total sum value"}"}],"libraries":"{"name":"chart.js","version":"4.4.1","globalVariable":"Chart"}","dependencies":[],"code":"function SimpleChart({\n  entityName,\n  data,\n  groupBy,\n  stackBy,\n  valueField,\n  aggregateMethod = ''count'',\n  chartType = ''auto'',\n  title,\n  height = 400,\n  sortBy = undefined,\n  sortOrder = ''asc'',\n  limit,\n  colors,\n  showLegend = true,\n  legendPosition = ''auto'', // New prop: ''auto'', ''top'', ''bottom'', ''left'', ''right''\n  legendFontSize = 12, // New prop for legend font size\n  showDataLabels = false,\n  enableExport = true,\n  onDataPointClick,\n  onChartRendered,\n  utilities,\n  styles,\n  components,\n  callbacks,\n  savedUserSettings,\n  onSaveUserSettings\n}) {\n  // Always use the MJ unwrapLibraryComponents function to get components from global libraries\n  // This ensures that various library build/package formats are handled correctly and transparently\n  // Chart.js is available as a global ''Chart'' based on the spec''s globalVariable setting\n  // Since Chart.js exports a single constructor function, unwrapLibraryComponents returns it for the requested name\n  const { Chart: ChartJS } = unwrapLibraryComponents(Chart, ''Chart'');\n  \n  const canvasRef = React.useRef(null);\n  const chartInstanceRef = React.useRef(null);\n  const "error, setError" = React.useState(null);\n  const "entityInfo, setEntityInfo" = React.useState(null);\n\n  // Modern color palette - balanced saturation for polished dashboards\n  const defaultColors = "\n    ''#4a90d9'', // Steel blue\n    ''#6abf69'', // Soft green\n    ''#f0a030'', // Warm amber\n    ''#e8665d'', // Soft red\n    ''#9270ca'', // Soft purple\n    ''#45b5b5'', // Teal\n    ''#e87040'', // Soft coral\n    ''#5c7cfa'', // Periwinkle\n    ''#8cc63f'', // Olive green\n    ''#d66ba0''  // Dusty rose\n  ";\n\n  // Load entity metadata\n  React.useEffect(() => {\n    if (!entityName || !utilities?.md?.Entities) {\n      if (!entityName) console.error(''Entity name not provided'');\n      if (!utilities?.md?.Entities) console.error(''Entity metadata not loaded.'');\n      return;\n    }\n    \n    const entity = utilities.md."Entities".find(e => e."Name" === entityName);\n    if (entity) {\n      setEntityInfo(entity);\n    }\n  }, "entityName, utilities");\n\n  // Helper function to format values based on type\n  const formatValue = (value, isDate = false, isCurrency = false) => {\n    if (value == null) return ''N/A'';\n    \n    if (isDate) {\n      try {\n        const date = new Date(value);\n        if (isNaN(date.getTime())) return value;\n        return date.toLocaleDateString(''en-US'', { \n          month: ''short'', \n          day: ''numeric'',\n          year: ''numeric''\n        });\n      } catch {\n        return value;\n      }\n    }\n    \n    if (isCurrency || (typeof value === ''number'' && valueField && valueField.toLowerCase().includes(''amount''))) {\n      if (typeof value === ''number'') {\n        return new Intl."NumberFormat"(''en-US'', {\n          style: ''currency'',\n          currency: ''USD'',\n          minimumFractionDigits: 0,\n          maximumFractionDigits: 0\n        }).format(value);\n      }\n    }\n    \n    if (typeof value === ''number'') {\n      // Format large numbers with commas\n      return new Intl."NumberFormat"(''en-US'').format(value);\n    }\n    \n    return value;\n  };\n\n  // Process and aggregate data\n  const processData = React.useMemo(() => {\n    if (!data || !Array.isArray(data) || data.length === 0) {\n      return { chartData: [], categories: [], values: [], datasets: [], isEmpty: true, isDateField: false };\n    }\n\n    try {\n      // Validate that fields exist in the actual data, not just entity metadata\n      // This allows for calculated fields from queries that don''t exist in base entity\n      if (data.length > 0) {\n        // Check if fields exist in data\n        if (!(groupBy in data[0])) {\n          const error = `Field \"$' || '{groupBy}\" not found in data. Available fields: $' || '{Object.keys(data[0]).join('', '')}`;\n          console.error(error);\n          setError(error);\n          return { chartData: [], categories: [], values: [], datasets: [], isEmpty: true, isDateField: false };\n        }\n\n        if (stackBy && !(stackBy in data[0])) {\n          const error = `Stack field \"$' || '{stackBy}\" not found in data. Available fields: $' || '{Object.keys(data[0]).join('', '')}`;\n          console.error(error);\n          setError(error);\n          return { chartData: [], categories: [], values: [], datasets: [], isEmpty: true, isDateField: false };\n        }\n\n        if (valueField && !(valueField in data[0])) {\n          const error = `Value field \"$' || '{valueField}\" not found in data. Available fields: $' || '{Object.keys(data[0]).join('', '')}`;\n          console.error(error);\n          setError(error);\n          return { chartData: [], categories: [], values: [], datasets: [], isEmpty: true, isDateField: false };\n        }\n      }\n\n      // Check if groupBy field is a date field using entity metadata\n      let isDateField = false;\n      if (entityInfo && entityInfo."Fields") {\n        const fieldInfo = entityInfo."Fields".find(f => f."Name" === groupBy);\n        isDateField = fieldInfo && (fieldInfo."Type" === ''datetime'' || fieldInfo."Type" === ''date'');\n      }\n      \n      // Fallback to value-based detection if no metadata available\n      if (!isDateField && data.length > 0) {\n        const sampleValue = data[0]"groupBy";\n        isDateField = sampleValue && (\n          sampleValue instanceof Date ||\n          (typeof sampleValue === ''string'' && sampleValue.length >= 8 && !isNaN(Date.parse(sampleValue)))\n        );\n      }\n\n      // STACKED MODE: If stackBy is provided, create multiple datasets\n      if (stackBy) {\n        // Collect all unique primary categories (X-axis)\n        const categoriesSet = new Set();\n        data.forEach(record => {\n          const key = record"groupBy" || ''Unknown'';\n          categoriesSet.add(key);\n        });\n\n        let categories = Array.from(categoriesSet);\n\n        // Sort categories if requested\n        if (sortBy === ''label'') {\n          categories.sort((a, b) => {\n            const comparison = String(a).localeCompare(String(b));\n            return sortOrder === ''asc'' ? comparison : -comparison;\n          });\n        }\n\n        // Apply limit to categories\n        if (limit && limit > 0) {\n          categories = categories.slice(0, limit);\n        }\n\n        // Collect all unique stack values (series/colors)\n        const stackValuesSet = new Set();\n        data.forEach(record => {\n          const stackValue = record"stackBy" || ''Unknown'';\n          stackValuesSet.add(stackValue);\n        });\n        const stackValues = Array.from(stackValuesSet).sort();\n\n        // Group data by both primary category AND stack value\n        const grouped = {};\n        data.forEach(record => {\n          const categoryKey = record"groupBy" || ''Unknown'';\n\n          // Skip if category was filtered out by limit\n          if (!categories.includes(categoryKey)) return;\n\n          const stackValue = record"stackBy" || ''Unknown'';\n          const key = `$' || '{categoryKey}|||$' || '{stackValue}`;\n\n          if (!grouped"key") {\n            grouped"key" = {\n              category: categoryKey,\n              stackValue: stackValue,\n              records: [],\n              value: 0\n            };\n          }\n          grouped"key".records.push(record);\n        });\n\n        // Aggregate based on method\n        Object.keys(grouped).forEach(key => {\n          const group = grouped"key";\n\n          if (aggregateMethod === ''count'') {\n            group.value = group.records.length;\n          } else if (valueField) {\n            const values = group.records\n              .map(r => parseFloat(r"valueField"))\n              .filter(v => !isNaN(v));\n\n            if (values.length > 0) {\n              switch (aggregateMethod) {\n                case ''sum'':\n                  group.value = values.reduce((a, b) => a + b, 0);\n                  break;\n                case ''average'':\n                  group.value = values.reduce((a, b) => a + b, 0) / values.length;\n                  break;\n                case ''min'':\n                  group.value = Math.min(...values);\n                  break;\n                case ''max'':\n                  group.value = Math.max(...values);\n                  break;\n                default:\n                  group.value = values.length;\n              }\n            }\n          }\n        });\n\n        // Create datasets array - one dataset per stack value\n        const datasets = stackValues.map((stackValue, stackIndex) => {\n          const datasetValues = categories.map(category => {\n            const key = `$' || '{category}|||$' || '{stackValue}`;\n            return grouped"key" ? grouped"key".value : 0;\n          });\n\n          return {\n            label: String(stackValue),\n            data: datasetValues,\n            backgroundColor: (colors || defaultColors)"stackIndex % (colors || defaultColors).length",\n            borderColor: (colors || defaultColors)"stackIndex % (colors || defaultColors).length",\n            borderWidth: 1\n          };\n        });\n\n        return {\n          chartData: Object.values(grouped),\n          categories: categories.map(c => String(c)),\n          values: [], // Not used in stacked mode\n          datasets: datasets,\n          isEmpty: false,\n          isDateField\n        };\n      }\n\n      // NON-STACKED MODE: Original single-series logic\n      const grouped = {};\n\n      data.forEach(record => {\n        const key = record"groupBy" || ''Unknown'';\n\n        if (!grouped"key") {\n          grouped"key" = {\n            label: key,\n            records: [],\n            value: 0\n          };\n        }\n        grouped"key".records.push(record);\n      });\n\n      // Aggregate based on method\n      Object.keys(grouped).forEach(key => {\n        const group = grouped"key";\n        \n        if (aggregateMethod === ''count'') {\n          group.value = group.records.length;\n        } else if (valueField) {\n          const values = group.records\n            .map(r => parseFloat(r"valueField"))\n            .filter(v => !isNaN(v));\n          \n          if (values.length > 0) {\n            switch (aggregateMethod) {\n              case ''sum'':\n                group.value = values.reduce((a, b) => a + b, 0);\n                break;\n              case ''average'':\n                group.value = values.reduce((a, b) => a + b, 0) / values.length;\n                break;\n              case ''min'':\n                group.value = Math.min(...values);\n                break;\n              case ''max'':\n                group.value = Math.max(...values);\n                break;\n              default:\n                group.value = values.length;\n            }\n          }\n        }\n      });\n\n      // Convert to array\n      let dataArray = Object.values(grouped);\n\n      // Only sort if explicitly requested (preserves input order by default)\n      if (sortBy === ''label'') {\n        dataArray.sort((a, b) => {\n          const comparison = String(a.label).localeCompare(String(b.label));\n          return sortOrder === ''asc'' ? comparison : -comparison;\n        });\n      } else if (sortBy === ''value'') {\n        dataArray.sort((a, b) => {\n          const comparison = a.value - b.value;\n          return sortOrder === ''asc'' ? comparison : -comparison;\n        });\n      }\n      // If sortBy is undefined/null, preserve the input order\n\n      // Apply limit if specified\n      if (limit && limit > 0) {\n        dataArray = dataArray.slice(0, limit);\n      }\n\n      const categories = dataArray.map(d => String(d.label));\n      const values = dataArray.map(d => d.value);\n\n      return {\n        chartData: dataArray,\n        categories,\n        values,\n        datasets: [], // Empty in non-stacked mode\n        isEmpty: false,\n        isDateField\n      };\n    } catch (err) {\n      console.error(''Error processing chart data:'', err);\n      setError(err.message);\n      return { chartData: [], categories: [], values: [], datasets: [], isEmpty: true, isDateField: false };\n    }\n  }, "data, groupBy, stackBy, valueField, aggregateMethod, sortBy, sortOrder, limit, entityInfo");\n\n  // Determine chart type automatically\n  const determineChartType = () => {\n    if (chartType !== ''auto'') {\n      // Map ''donut'' to Chart.js ''doughnut'' \n      if (chartType === ''donut'') return ''doughnut'';\n      // Map ''column'' to Chart.js ''bar''\n      if (chartType === ''column'') return ''bar'';\n      return chartType;\n    }\n    \n    // Check if groupBy field is a date field using entity metadata\n    let isDateField = false;\n    if (entityInfo && entityInfo."Fields") {\n      const fieldInfo = entityInfo."Fields".find(f => f."Name" === groupBy);\n      isDateField = fieldInfo && (fieldInfo."Type" === ''datetime'' || fieldInfo."Type" === ''date'');\n    }\n    \n    // Fallback to value-based detection if no metadata available\n    if (!isDateField && data && data.length > 0) {\n      const sampleValue = data[0]"groupBy";\n      isDateField = sampleValue && (\n        sampleValue instanceof Date ||\n        (typeof sampleValue === ''string'' && sampleValue.length >= 8 && !isNaN(Date.parse(sampleValue)))\n      );\n    }\n    \n    if (isDateField) {\n      return ''line'';\n    }\n    \n    // Use pie for small number of categories (preferred over doughnut)\n    if (processData.categories && processData.categories.length <= 5) {\n      return ''pie'';\n    }\n    \n    // Default to bar chart\n    return ''bar'';\n  };\n\n  const actualChartType = determineChartType();\n\n  // Generate chart configuration for Chart.js\n  const getChartConfig = () => {\n    const isPieOrDoughnut = actualChartType === ''pie'' || actualChartType === ''doughnut'';\n    const isLineOrArea = actualChartType === ''line'' || actualChartType === ''area'';\n    const isStacked = stackBy && processData.datasets && processData.datasets.length > 0;\n\n    const config = {\n      type: actualChartType === ''area'' ? ''line'' : actualChartType,\n      data: {\n        labels: processData.categories,\n        datasets: isStacked\n          ? processData.datasets // Use pre-built datasets for stacked mode\n          : "{\n              label: valueField || ''Count'',\n              data: processData.values,\n              backgroundColor: isPieOrDoughnut\n                ? (colors || defaultColors).slice(0, processData.values.length)\n                : isLineOrArea\n                  ? ''rgba(24, 144, 255, 0.2)''\n                  : (colors || defaultColors).slice(0, processData.values.length), // Different color for each bar\n              borderColor: isPieOrDoughnut\n                ? ''#fff''\n                : isLineOrArea\n                  ? (colors || defaultColors)[0"\n                  : (colors || defaultColors).slice(0, processData.values.length),\n              borderWidth: isPieOrDoughnut ? 2 : isLineOrArea ? 3 : 0,\n              borderRadius: isPieOrDoughnut || isLineOrArea ? undefined : 4,\n              fill: actualChartType === ''area'',\n              tension: isLineOrArea ? 0.35 : undefined,\n              pointRadius: isLineOrArea ? 4 : undefined,\n              pointBackgroundColor: isLineOrArea ? ''#f