     } else {\n              total = processData.values.reduce((a, b) => a + b, 0);\n            }\n\n            onDataPointClick({\n              chartType: actualChartType,\n              series: isStacked ? clickedLabel : (valueField || ''Count''),\n              label: clickedLabel,\n              value: clickedValue,\n              records: clickedRecords,\n              percentage: (clickedValue / total) * 100\n            });\n          }\n        },\n        plugins: {\n          title: {\n            display: !!title,\n            text: title,\n            font: {\n              size: 16,\n              weight: 600\n            },\n            padding: {\n              bottom: 10\n            }\n          },\n          legend: {\n            display: showLegend && (isPieOrDoughnut || processData.categories.length <= 10),\n            position: legendPosition === ''auto''\n              ? (isPieOrDoughnut ? ''bottom'' : ''top'')\n              : legendPosition,\n            labels: {\n              usePointStyle: true,\n              pointStyle: ''circle'',\n              padding: 16,\n              font: {\n                size: legendFontSize\n              }\n            }\n          },\n          datalabels: showDataLabels ? {\n            display: true,\n            formatter: (value) => formatValue(value),\n            color: isPieOrDoughnut ? ''#fff'' : ''#666''\n          } : undefined,\n          tooltip: {\n            backgroundColor: ''rgba(30, 30, 30, 0.9)'',\n            titleFont: {\n              size: 13,\n              weight: 600\n            },\n            bodyFont: {\n              size: 13\n            },\n            padding: { top: 10, bottom: 10, left: 14, right: 14 },\n            cornerRadius: 8,\n            displayColors: true,\n            usePointStyle: true,\n            boxPadding: 6,\n            callbacks: {\n              title: (tooltipItems) => {\n                const raw = tooltipItems[0]?.label || '''';\n                if (processData.isDateField && raw !== ''Unknown'') {\n                  const date = new Date(raw);\n                  if (!isNaN(date.getTime())) {\n                    return date.toLocaleDateString(''en-US'', { month: ''short'', day: ''numeric'', year: ''numeric'' });\n                  }\n                }\n                return raw;\n              },\n              label: (context) => {\n                const label = context.dataset.label || '''';\n                const value = formatValue(context.parsed.y !== undefined ? context.parsed.y : context.parsed);\n                return `$' || '{label}: $' || '{value}`;\n              }\n            }\n          }\n        }\n      }\n    };\n\n    // Add scales for non-pie/doughnut charts\n    if (!isPieOrDoughnut) {\n      config.options.scales = {\n        y: {\n          beginAtZero: true,\n          stacked: isStacked,\n          border: { display: false },\n          grid: {\n            color: ''#f0f0f0'',\n            drawTicks: false\n          },\n          ticks: {\n            padding: 8,\n            callback: (value) => formatValue(value)\n          }\n        },\n        x: {\n          stacked: isStacked,\n          border: { display: false },\n          grid: { display: false },\n          ticks: {\n            autoSkip: true,\n            maxRotation: 60,\n            minRotation: 0,\n            maxTicksLimit: 20,\n            padding: 4,\n            font: {\n              size: 11\n            },\n            callback: function(value) {\n              const label = this.getLabelForValue(value);\n              // Format date values for display on the axis\n              if (processData.isDateField && typeof label === ''string'' && label !== ''Unknown'') {\n                const date = new Date(label);\n                if (!isNaN(date.getTime())) {\n                  return date.toISOString().split(''T'')[0];\n                }\n              }\n              if (typeof label === ''string'' 